/* Basic styling for the game */
body {
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    margin: 0;
    background-color: #222;
    font-family: 'Press Start 2P', cursive; /* Use a retro font like 'Press Start 2P' from Google Fonts or monospace */
    color: #eee;
    text-align: center;
    user-select: none; /* Prevent text selection */
}

.game-container {
    background-color: #333;
    padding: 20px;
    border-radius: 8px;
    box-shadow: 0 0 15px rgba(0, 255, 0, 0.5);
    border: 2px solid #0f0; /* Retro green border */
}

h1 {
    color: #0f0;
    margin-bottom: 15px;
}

.score-display {
    font-size: 1.2em;
    margin-bottom: 10px;
    color: #fff;
}

canvas {
    background-color: #111; /* Dark background for the game board */
    border: 2px solid #0f0;
    display: block;
    margin: 0 auto 15px auto;
}

button {
    background-color: #0f0;
    color: #111;
    border: none;
    padding: 10px 20px;
    font-size: 1.1em;
    cursor: pointer;
    border-radius: 5px;
    transition: background-color 0.3s ease;
}

button:hover {
    background-color: #0c0;
}

