let food = {};
let dx = 0; // x velocity
let dy = 0; // y velocity
let score = 0;
let gameInterval;
let isGameOver = false;

// Function to draw the game board and elements (will be expanded)
function drawGame() {
    // Clear the canvas
    ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

    // Draw the background grid (optional, but good for visualization)
    for (let i = 0; i < TILE_COUNT; i++) {
        for (let j = 0; j < TILE_COUNT; j++) {
            ctx.fillStyle = (i + j) % 2 === 0 ? '#111' : '#1a1a1a'; // Alternating dark colors
            ctx.fillRect(i * GRID_SIZE, j * GRID_SIZE, GRID_SIZE, GRID_SIZE);
        }
    }
}

// Call drawGame initially to set up the board
drawGame();

