const gameCanvas = document.getElementById('gameCanvas');
const ctx = gameCanvas.getContext('2d');
const scoreDisplay = document.getElementById('score');
const startButton = document.getElementById('startButton');

// Game constants
const CANVAS_SIZE = 400;
const GRID_SIZE = 20;
const TILE_COUNT = CANVAS_SIZE / GRID_SIZE;

// Initial game state variables
let snake = [];
let food = {};
let dx = 0;
let dy = 0;
let score = 0;
let gameInterval;
let isGameOver = false;
let changingDirection = false;

// Initialize the snake
function initSnake() {
    snake = [];
    // Start the snake in the middle, 3 segments long
    snake.push({ x: 10 * GRID_SIZE, y: 10 * GRID_SIZE });
    snake.push({ x: 9 * GRID_SIZE, y: 10 * GRID_SIZE });
    snake.push({ x: 8 * GRID_SIZE, y: 10 * GRID_SIZE });
    // Initial direction - to the right
    dx = GRID_SIZE; 
    dy = 0;
}

// Generate random food coordinates
function generateFood() {
    let foodX, foodY;
    let collisionWithSnake;
    do {
        foodX = Math.floor(Math.random() * TILE_COUNT) * GRID_SIZE;
        foodY = Math.floor(Math.random() * TILE_COUNT) * GRID_SIZE;
        collisionWithSnake = snake.some(segment => segment.x === foodX && segment.y === foodY);
    } while (collisionWithSnake);

    food = { x: foodX, y: foodY };
}

// Draw the snake on the canvas
function drawSnake() {
    snake.forEach(segment => {
        ctx.fillStyle = '#0f0'; // Green color for the snake
        ctx.strokeStyle = '#000'; // Black border for segments
        ctx.fillRect(segment.x, segment.y, GRID_SIZE, GRID_SIZE);
        ctx.strokeRect(segment.x, segment.y, GRID_SIZE, GRID_SIZE);
    });
}

// Draw the food on the canvas
function drawFood() {
    ctx.fillStyle = '#f00'; // Red color for food
    ctx.strokeStyle = '#000';
    ctx.fillRect(food.x, food.y, GRID_SIZE, GRID_SIZE);
    ctx.strokeRect(food.x, food.y, GRID_SIZE, GRID_SIZE);
}

// Main game update logic
function updateGame() {
    if (isGameOver) return;

    changingDirection = false; // Reset flag at the start of update

    // Calculate new head position
    const head = { x: snake[0].x + dx, y: snake[0].y + dy };

    // Add new head to the beginning of the snake array
    snake.unshift(head);

    // Remove the tail (for now, will change when eating food)
    snake.pop();

    drawGame(); // Redraw everything
}

// Function to draw the game board and elements
function drawGame() {
    // Clear the canvas
    ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

    // Draw the background grid
    for (let i = 0; i < TILE_COUNT; i++) {
        for (let j = 0; j < TILE_COUNT; j++) {
            ctx.fillStyle = (i + j) % 2 === 0 ? '#111' : '#1a1a1a'; // Alternating dark colors
            ctx.fillRect(i * GRID_SIZE, j * GRID_SIZE, GRID_SIZE, GRID_SIZE);
        }
    }

    drawSnake(); // Draw the snake
    drawFood();  // Draw the food
}

// Handle keyboard input for snake direction
document.addEventListener('keydown', e => {
    if (changingDirection) return;
    changingDirection = true;

    const keyPressed = e.key;

    const hasMovedHorizontally = dx !== 0;
    const hasMovedVertically = dy !== 0;

    if (keyPressed === 'ArrowLeft' && !hasMovedHorizontally) {
        dx = -GRID_SIZE;
        dy = 0;
    } else if (keyPressed === 'ArrowRight' && !hasMovedHorizontally) {
        dx = GRID_SIZE;
        dy = 0;
    } else if (keyPressed === 'ArrowUp' && !hasMovedVertically) {
        dx = 0;
        dy = -GRID_SIZE;
    } else if (keyPressed === 'ArrowDown' && !hasMovedVertically) {
