    if (changingDirection) return;
    changingDirection = true;

    const keyPressed = e.key;

    const hasMovedHorizontally = dx !== 0;
    const hasMovedVertically = dy !== 0;

    if (keyPressed === 'ArrowLeft' && !hasMovedHorizontally) {
        dx = -GRID_SIZE;
        dy = 0;
    } else if (keyPressed === 'ArrowRight' && !hasMovedHorizontally) {
        dx = GRID_SIZE;
        dy = 0;
    } else if (keyPressed === 'ArrowUp' && !hasMovedVertically) {
        dx = 0;
        dy = -GRID_SIZE;
    } else if (keyPressed === 'ArrowDown' && !hasMovedVertically) {
        dx = 0;
        dy = GRID_SIZE;
    }
});

// Function to start the game
function startGame() {
    isGameOver = false;
    score = 0;
    scoreDisplay.textContent = score;
    initSnake();
    generateFood();
    drawGame();
    if (gameInterval) clearInterval(gameInterval);
    gameInterval = setInterval(updateGame, 100);
}

// Attach event listener to start button
startButton.addEventListener('click', startGame);

// Call startGame initially to set up initial state without auto-playing
startGame();
clearInterval(gameInterval);

